<div class="modal fade" id="tcMembersModal" tabindex="-1"><div class="modal-dialog modal-dialog-centered modal-lg"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Members</h5><button class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input class="form-control mb-2" id="tcAddMemberSearch" placeholder="Search users to add"><div id="tcAddMemberResults" class="tc-modal-search-results"></div><hr><?php foreach (($members ?? []) as $member): ?><div class="tc-user-result"><img class="tc-avatar tc-avatar--sm" src="<?php echo html_escape($member['avatar_url'] ?? team_chat_user_avatar_url($member['profile_image'] ?? '', $member['fullname'] ?? '')); ?>" alt=""><div><div class="tc-user-result__name"><?php echo html_escape($member['fullname'] ?? 'User'); ?></div><div class="tc-user-result__meta"><?php echo html_escape($member['role'] ?? 'member'); ?></div></div><?php if ((int)($member['user_id'] ?? 0) !== (int)($user_id ?? 0)): ?><button class="btn btn-sm btn-outline-danger ms-auto" data-remove-member="<?php echo (int)$member['user_id']; ?>">Remove</button><?php endif; ?></div><?php endforeach; ?></div><div class="modal-footer"><button class="btn btn-secondary" data-bs-dismiss="modal">Close</button></div></div></div></div>
